import pytest

from conftest import build_cache, run_script, read_json, repo_pollution
import graphify_lib

AC_UID = "f50385d4cddc0b2b"
AC_TYPE = "data"


def test_AC2(real_binary, fixture_env):
    """
    GIVEN: real graph.json (links + nodes with id) built by a real graphify update
    WHEN:  graphify-query.py (Step 1.5) builds structural_context with gate enabled and >=1 anchor present
    THEN:  (a) parses edges from links (source/target/relation) read directly from graph.json (deterministic primary signal); (b) MUST invoke real `graphify query "<q>" --graph <cacheDir/graph.json> --budget N` at least once where <q> contains >=1 anchor EXTRACTED from the same input under test and present/resolvable in graph.json (NOT a hardcoded/irrelevant query), and MUST consume its real stdout into structural_context attributable to that exact invocation; (c) structural_context <=2000 tokens, ambiguity+advisory preserved, NO argv references --file/--format/--cache-dir. PROOF-OF-CALL: recorded argv contains [graphify,query,...] whose executable resolves to the real binary and --graph==real graph.j…
    """
    build_cache(fixture_env, real_binary)
    # Requirement mentions mod_a.py — an anchor present in the built graph.
    req = fixture_env["src"] / "req.md"
    req.write_text("Please change mod_a.py so alpha() returns 2.\n", encoding="utf-8")

    r = run_script("graphify-query.py", ["--task-id", "t1", "--requirement-file", str(req)],
                   fixture_env["env"])
    assert r.returncode == 0, f"query must exit 0 (advisory): {r.stderr}"

    pq = read_json(fixture_env["registry"] / "graphify" / "pre_query.json")
    sc = pq["structural_context"]

    # (a) edges parsed from node-link `links` (source/target/relation) — primary signal.
    assert sc["import_graph_excerpt"], "import_graph_excerpt must be populated from graph.json links"
    assert any("-->" in line for line in sc["import_graph_excerpt"])

    # (b) real graphify query invoked at least once with an input-derived anchor.
    qr = sc["graphify_query_results"]
    assert qr, "MUST invoke real graphify query at least once on the healthy path"
    rec = qr[0]
    argv = rec["argv"]
    assert argv[0] == "graphify" and argv[1] == "query"
    assert "--graph" in argv and str(fixture_env["graph_json"]) in argv
    assert "--budget" in argv
    # query string is an input-derived anchor present/resolvable in graph.json.
    assert rec["anchor"] == "mod_a.py"
    assert pq["query_cli_status"] == graphify_lib.STATUS_OK
    # consumed real stdout attributable to that invocation (the anchor appears in the BFS Start line).
    assert "mod_a.py" in rec.get("output", "")

    # (c) token cap + no fictional flags.
    assert sc["token_count"] <= 2000
    blob = " ".join(argv)
    for bad in ("--file", "--format", "--cache-dir"):
        assert bad not in blob
    assert repo_pollution(fixture_env["src"]) == []
